// Student's exam score out of 100
const score: number = 87;
// Variable to hold the letter grade
let grade: string = '';
// Check each threshold from highest to lowest
if (score >= 90) {
  grade = 'A'; // Score is 90 or above
} else if (score >= 80) {
  grade = 'B'; // Score is 80 to 89
} else if (score >= 70) {
  grade = 'C'; // Score is 70 to 79
} else if (score >= 60) {
  grade = 'D'; // Score is 60 to 69
} else {
  grade = 'F'; // Score is below 60
}
console.log('Score:', score, 'Grade:', grade);
// Expected: Score: 87 Grade: B
